// src/components/CarSprite/CarSprite.jsx
import React, { useMemo } from 'react';
import './CarSprite.scss';

const CarSprite = ({ direction = 0, color = '#FFEB3B', scale = 1 }) => {
  // 72 frames no total para 360 graus
  const TOTAL_FRAMES = 72;
  const FRAME_WIDTH = 60; // Largura aproximada de cada frame em px (ajuste se necessário)
  const FRAME_HEIGHT = 60; // Altura do frame
  
  // Calcula qual frame mostrar baseado na direção (0 a 360)
  // Ex: 0 graus = frame 0, 180 graus = frame 36
  const frameIndex = Math.min(
    Math.floor(((direction % 360) / 360) * TOTAL_FRAMES), 
    TOTAL_FRAMES - 1
  );

  // Calcula a posição horizontal do background (negative value)
  const backgroundPositionX = -(frameIndex * FRAME_WIDTH);

  const spriteStyle = {
    width: `${FRAME_WIDTH * scale}px`,
    height: `${FRAME_HEIGHT * scale}px`,
    backgroundImage: `url(${process.env.PUBLIC_URL}/sprites/car-sprite.png)`,
    backgroundPosition: `${backgroundPositionX}px 0`,
    backgroundSize: `${TOTAL_FRAMES * FRAME_WIDTH}px ${FRAME_HEIGHT}px`,
    // Transição suave se a direção mudar bruscamente (opcional)
    transition: 'background-position 0.1s linear', 
  };

  return (
    <div className="car-sprite-container" style={spriteStyle}>
      {/* Indicador de cor do veículo (bolinha embaixo) */}
      <div 
        className="car-indicator" 
        style={{ backgroundColor: color }} 
      />
    </div>
  );
};

export default CarSprite;
